const sessionId = $('Webhook').first().json.body.message.from.id;
const userMessage = $('Webhook').first().json.body.message.text || $('Webhook').first().json.body.message.photo_url;
const event = $('Webhook').first().json.body.event_name;

return {
  sessionId,
  userMessage,
  event
};

// n8n Function: session starts at RECEIPT, ends right before the next /done
// Fix: normalize order (many inputs are newest-first) before building the session.

const items = $input.all();
if (!items || items.length === 0) {
  return [{ json: { error: 'No message history', receipt: null, links: null } }];
}

const txt = (it) => it?.json?.text ?? '';
const isReceipt = (t) => /^CP\d{2}-[JT][A-Z0-9]+$/i.test((t || '').trim());
const isDone = (t) => ((t || '').trim() === '/done');

// Detect order and normalize to chronological (oldest → newest)
let ordered = items.slice();
const firstDone = ordered.findIndex(it => isDone(txt(it)));
const firstReceipt = ordered.findIndex(it => isReceipt(txt(it)));

if (firstDone !== -1 && firstReceipt !== -1 && firstDone < firstReceipt) {
  // Likely newest-first → reverse to chronological
  ordered = ordered.reverse();
}

// Build sessions: [receipt ... messages ...] until the next /done (exclusive)
let sessions = [];
let currentReceiptIndex = null;

for (let i = 0; i < ordered.length; i++) {
  const t = txt(ordered[i]);

  if (isReceipt(t)) {
    currentReceiptIndex = i;      // mark start at receipt
    continue;
  }

  if (isDone(t) && currentReceiptIndex !== null) {
    // slice includes the receipt, up to but NOT including /done
    sessions.push({
      receiptIndex: currentReceiptIndex,
      doneIndex: i,
      messages: ordered.slice(currentReceiptIndex, i),
    });
    currentReceiptIndex = null;
  }
}

// No complete session
if (sessions.length === 0) {
  const hasReceipt = ordered.some(it => isReceipt(txt(it)));
  const hasDone2 = ordered.some(it => isDone(txt(it)));
  if (hasReceipt && !hasDone2) {
    return [{ json: { error: 'Session active, waiting for /done', receipt: null, links: null, status: 'active' } }];
  }
  return [{ json: { error: 'No complete session found', receipt: null, links: null } }];
}

// Pick the latest complete session (highest doneIndex in chronological order)
const latest = sessions.reduce((a, b) => (a.doneIndex > b.doneIndex ? a : b));

let receipt = null;
const links = [];
const urlRegex = /https?:\/\/\S+/ig;

for (const item of latest.messages) {
  const t = (txt(item) || '').trim();
  if (!t || t.startsWith('/')) continue;

  if (!receipt && isReceipt(t)) {
    receipt = t.toUpperCase();
    continue;
  }

  const ms = t.match(urlRegex);
  if (ms) for (const u of ms) links.push(u);
}

const uniqueLinks = [...new Set(links)];

if (!receipt) {
  return [{ json: { error: 'No receipt in session', receipt: null, links: uniqueLinks.length ? uniqueLinks.join(',') : null } }];
}
if (uniqueLinks.length === 0) {
  return [{ json: { error: 'No links in session', receipt, links: null } }];
}

return [{
  json: {
    error: null,
    receipt,
    links: uniqueLinks.join(','),
    linkCount: uniqueLinks.length,
    status: 'complete',
  },
}];

// Input: { links_line: "https://a.jpg, https://b.png, ..."}
const raw = $('addReceiptHistories').first().json.links || '';
const split = raw
  .split(/[,\s]+/)           // phẩy, xuống dòng, khoảng trắng
  .map(s => s.trim())
  .filter(Boolean);

// Loại trùng, giữ thứ tự
const urls = [...new Set(split)];

// Trả về mỗi item 1 URL
return urls.map((u, i) => ({ json: { url: u, idx: i }}));

