// Mode: Run once for each item
// Input: $json.email (ví dụ "aBcD@phongvu-mna.vn")
// Output: { email: "abcd@phongvu-mna.vn" }

const s = String($input.first().json.body.message.text).trim();
return { json: { email: s.replace(/\s+/g, '').toLowerCase() } };

// Mode: Run once for each item
// Input text in $json.text (fallback: message/content)
// Accepts "/get CPxx-Jxxxxxxxx" in any case; output always UPPERCASE.

const s = String($json.text ?? $json.message ?? $json.content ?? '').trim();

// regex: CP + 2 digits, hyphen, J + 8 digits (case-insensitive)
const m = s.match(/\bcp\d{2}-j\d{8}\b/i);

return [{
  json: {
    receipt: m ? m[0].toUpperCase() : ''
  }
}];

const items = $input.all();

// Debug: Log số lượng messages
console.log(`Total messages: ${items.length}`);

if (!items || items.length === 0) {
  return [{
    json: {
      error: 'No message history found',
      choice: null,
      receipt: null,
      fromID: null
    }
  }];
}

let choice = null;
let receipt = null;
const fromID = items[0]?.json?.fromID || null;

// Duyệt từ tin nhắn mới nhất (index 0) đến cũ nhất
for (let i = 0; i < items.length; i++) {
  const text = items[i].json.text?.trim();

  if (!text) continue;

  // Tìm choice (chỉ chứa số 0, 1, 2, hoặc 3)
  if (choice === null && /^[0-3]$/.test(text)) {
    choice = text;
    console.log(`Found choice: ${choice} at index ${i}`);
  }

  // Tìm receipt trong lệnh /get
  if (receipt === null && text.startsWith('/get')) {
    // Tách lấy phần sau /get
    const afterGet = text.substring(4).trim();
    // Chuẩn hóa về uppercase
    const normalizedText = afterGet.toUpperCase();
    // Kiểm tra pattern CPxx-Jxxxxxxxx
    const match = normalizedText.match(/CP\d+-J\w+/);
    if (match) {
      receipt = match[0];
      console.log(`Found receipt: ${receipt} at index ${i}`);
    }
  }

  // Dừng khi đã tìm đủ cả 2
  if (choice !== null && receipt !== null) {
    break;
  }
}

// Validation và trả kết quả
if (choice === null && receipt === null) {
  return [{
    json: {
      error: 'No choice (0-3) or receipt found in recent messages',
      choice: null,
      receipt: null,
      fromID: fromID,
      messagesChecked: items.length
    }
  }];
}

if (choice === null) {
  return [{
    json: {
      error: 'No choice (0-3) found',
      choice: null,
      receipt: receipt,
      fromID: fromID,
      messagesChecked: items.length
    }
  }];
}

if (receipt === null) {
  return [{
    json: {
      error: 'No receipt found in /get command',
      choice: choice,
      receipt: null,
      fromID: fromID,
      messagesChecked: items.length
    }
  }];
}

// Success
console.log(`Success: choice=${choice}, receipt=${receipt}, fromID=${fromID}`);
return [{
  json: {
    error: null,
    choice: choice,
    receipt: receipt,
    fromID: fromID,
    messagesChecked: items.length,
    processedAt: new Date().toISOString()
  }
}];

